.darma-loader-darma-custom-596 {color: var(--loader-color, #059669);
  --loader-secondary-color: var(--loader-secondary-color, #2dd4bf);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 100px;
   height: 30px;
   display: flex;
}
.darma-loader-darma-custom-596:before, .darma-loader-darma-custom-596:after  {
  content: "";
   flex: 1;
   margin: 0 5px;
   background: currentColor;
   clip-path: polygon(0 10px,calc(100% - 15px) 10px,calc(100% - 15px) 0,100% 50%,calc(100% - 15px) 100%,calc(100% - 15px) calc(100% - 10px),0 calc(100% - 10px));
   animation: darma-loader-darma-custom-596-l3 .5s infinite alternate;
}
.darma-loader-darma-custom-596:after  {
  --s:-1;
}
@keyframes darma-loader-darma-custom-596-l3  {
  0% {transform: scaleX(var(--s,1)) translate(-4px)}
100%{transform: scaleX(var(--s,1)) translate( 4px)}
}

